#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; long long K; scanf("%d %lld", &N, &K);
        long long M = 1LL << N; // 2^N
        long long maxPairs = M >> 1; // 2^{N-1}
        long long pairs = K < maxPairs ? K : maxPairs;
        long long ans = pairs * 2LL * (M - 1);
        printf("%lld\n", ans);
    }
    return 0;
}

