const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let results = [];
for(let t=0; t<T; t++){
  const N = Number(input[idx++]);
  const K = Number(input[idx++]);
  const M = 1n << BigInt(N); // 2^N as BigInt
  const maxPairs = M >> 1n; // 2^{N-1}
  const pairs = K < Number(maxPairs) ? BigInt(K) : maxPairs;
  const ans = pairs * 2n * (M - 1n);
  results.push(ans.toString());
}
